import useThemeChanger from "./useThemeChanger.js";
import { Sunny, Moon } from "./icons/icons.js";

//import "./changeThemeButton.scss";

export default function ChangeThemeButton() {
  const [ theme, handleThemeChangerClick ] = useThemeChanger();
  return (
    <button className="change-theme flex-column justify-c br-rounded p-1" type="button" onClick={handleThemeChangerClick}>
      { theme === "dark" 
        ? <Sunny/> 
        : <Moon/>
      }
    </button>
  );
}
